import { Component, OnInit, ViewChild, AfterViewInit } from '@angular/core';
import { UIChart } from 'primeng/chart';
import pdfMake from 'pdfmake/build/pdfmake';
import pdfFonts from 'pdfmake/build/vfs_fonts';
pdfMake.vfs = pdfFonts.pdfMake.vfs;

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  data: any;
  options: any;
  @ViewChild('graf') graf: UIChart
  
  totalizer = {
    id: 'totalizer',
    beforeUpdate: chart => {
      let totals = {};
      let utmost = 0;

      chart.data.datasets.forEach((dataset, datasetIndex) => {
        if (dataset.type == 'bar') {
          if (chart.isDatasetVisible(datasetIndex)) {
            utmost = datasetIndex;
            dataset.data.forEach((value, index) => {
              totals[index] = (totals[index] || 0) + value;
            })
          }
        }
      });
  
      chart.$totalizer = {
        totals: totals,
        utmost: utmost
      }
    }
  };

  ngOnInit(): void {
    this.data = {
      labels: ['Janeiro','Fevereiro','Março','Abril','Maio','Junho','Julho', 'Agosto', 'Setembro','Outubro', 'Novembro', 'Dezembro'],
      datasets: [
        {
          type:             'line',
          label:            'Endividamento BVW',
          data:             this.getRandomArray(),
          backgroundColor:  '#2D313C',
          borderColor:      '#2D313C',
          fill:             false
        },
        {
          type:             'line',
          label:            'Vencidos BVW',
          data:             this.getRandomArray(),
          backgroundColor:  '#FFD100',
          borderColor:      '#FFD100',
          fill:             false
        },
        {
          type:             'bar',
          label:            'Prejuízo',
          data:             this.getRandomArray(),
          stack:            'stack1',
          yAxisID:          'bar-y-axis',
          backgroundColor:  'rgba(165, 0, 33, 1)',
          borderColor:      'rgba(165, 0, 33, 1)'
        },
        {
          type:             'bar',
          label:            'Vencidos',
          data:             this.getRandomArray(),
          stack:            'stack1',
          yAxisID:          'bar-y-axis',
          backgroundColor:  'rgba(226, 103, 0, 1)',
          borderColor:      'rgba(226, 103, 0, 1)'
        },
        {
          type:             'bar',
          label:            'À Vencer',
          data:             this.getRandomArray(),
          stack:            'stack1',
          yAxisID:          'bar-y-axis',
          backgroundColor:  'rgba(33, 165, 250, 1)',
          borderColor:      'rgba(33, 165, 250, 1)'
        },
        {
          type:             'bar',
          label:            'Outros',
          data:             this.getRandomArray(),
          stack:            'stack1',
          yAxisID:          'bar-y-axis',
          backgroundColor:  'rgba(191, 191, 191, 1)',
          borderColor:      'rgba(191, 191, 191, 1)'
        },
      ]
    }
    
    this.options = {
      elements: {
        line: {
          tension: 0
        }
      },
      legend: {
        position: 'bottom'
      },
      scales: {
        yAxes: [
          { 
            stacked: false,
            ticks: { stepSize: 10, min: 0, max: 200 }
          },
          {
            id: "bar-y-axis",
            stacked: true,
            display: false,
            ticks: { stepSize: 10, min: 0, max: 200 }
          }
        ]
      },
      plugins: {
        datalabels: {
          formatter: (value, ctx) => {
            const total = ctx.chart.$totalizer.totals[ctx.dataIndex]
            return total.toLocaleString()
          },
          align: 'end',
          anchor: 'end',
          display: function(ctx) {
            return ctx.datasetIndex === ctx.chart.$totalizer.utmost
          }
        }
      }
    };
  }

  getRandomInt() {
    const min = Math.ceil(15);
    const max = Math.floor(50);
    return Math.floor(Math.random() * (max - min)) + min;
  }

  getRandomArray() {
    return [
      this.getRandomInt(), this.getRandomInt(),
      this.getRandomInt(), this.getRandomInt(),
      this.getRandomInt(), this.getRandomInt(),
      this.getRandomInt(), this.getRandomInt(),
      this.getRandomInt(), this.getRandomInt(),
      this.getRandomInt(), this.getRandomInt()
    ];
  }

  getBase64Img() {
    var base64 = this.graf.getBase64Image()
    return base64
  }

  exportarPDF() {
    const documento = { 
      content: [
        'Exemplo exportação para PDF',
        {
          image: this.getBase64Img(),
          width:  500,
			    height: 300,
        }
      ]
    };
    
    const pdf = pdfMake.createPdf(documento);
    pdf.download();
   }
}
